blockquote.pre:
#include <print>
#include <ranges>

struct R {
  int* begin() = delete;
  int* end() = delete;
  const int* begin() const;
  const int* end() const;
};

int main() {
  const R r;
  static_assert(std::ranges::contiguous_range<decltype(r)>);

  for (auto&& elem : r)
    std::print("{} ", elem); // ok

  std::ranges::for_each(
    r, [](auto&& elem) { std::print("{} ", elem); }
  );                         // ok

  std::print("{}", r);       // not ok
}
